98	};
99	
100	function SegmentButton({ label, selected, onPress, testID }: SegmentButtonProps) {
101	  const bg = selected ? colors.primarySoft : colors.surface;
102	  const textColor = selected ? colors.primaryDeep : colors.ink;
103	  return (
