      testID={testID}
    >
      <Text style={[textStyles.display, styles.tileValue]} allowFontScaling={false}>
        {value}
      </Text>
      <Text style={[textStyles.caption, styles.tileLabel]}>{label}</Text>
    </View>
  );
}

