    padding: spacing.base,
    gap: spacing.xs,
  },
  tileValue: {
    color: colors.ink,
  },
  tileLabel: {
    color: colors.ink70,
  },
  errorBox: {
    padding: spacing.lg,
    alignItems: 'center',
  },
});

